;\n  }\n  \n  /* Cards */\n  .card {\n    margin-bottom: 15px;\n  }\n  .card-body, .card > div[class*=\"p-\"] {\n    padding: 15px !important;\n  }\n  \n  /* Buttons */\n  .btn {\n    padding: 12px 20px;\n    font-size: 12px;\n    height: auto;\n    min-height: 44px;\n  }\n  \n  /* Forms */\n  input[type=email], input[type=password], input[type=text], input[type=tel] {\n    height: 44px;\n    font-size: 16px;\n  }\n  \n  /* Text utilities */\n  .text-lg {\n    font-size: 18px;\n  }\n  .lead {\n    font-size: 14px;\n  }\n  .number {\n    font-size: 36px;\n    line-height: 45px;\n  }\n}\n\n/* Small Mobile (400px - 480px) */\n@include mobile{\n  /* Typography */\n  h1, .h1 {\n    font-size: 32px;\n    line-height: 36px;\n  }\n  h2, .h2 {\n    font-size: 26px;\n    line-height: 32px;\n  }\n  h3, .h3 {\n    font-size: 20px;\n    line-height: 26px;\n  }\n  h4, .h4 {\n    font-size: 17px;\n    line-height: 23px;\n  }\n  body {\n    font-size: 14px;\n  }\n\n  /* Navbar */\n  .navbar-brand img {\n    height: 60px !important;\n  }\n  .ml-lg-4 {\n    margin-left: 0 !important;\n  }\n  .navbar-collapse {\n    padding-top: 15px;\n  }\n  .dropdown-menu {\n    display: none;\n    text-align: center;\n  }\n  .navbar-nav li{\n    padding: 0px;\n  }\n\n  /* Hero Section */\n  .slider h1 {\n    font-size: 32px;\n    line-height: 38px;\n  }\n  .slider {\n    padding: 80px 15px !important;\n  }\n\n  /* Text utilities */\n  .text-lg {\n    font-size: 24px;\n    line-height: 32px;\n  }\n  .lead {\n    font-size: 14px;\n  }\n  .number {\n    font-size: 44px;\n    line-height: 55px;\n  }\n\n  /* Sections */\n  .section {\n    padding: 50px 0;\n  }\n  \n  /* Cards */\n  .card {\n    margin-bottom: 20px;\n  }\n  \n  /* Buttons */\n  .btn {\n    padding: 14px 25px;\n    font-size: 13px;\n    min-height: 44px;\n  }\n\n  /* Forms */\n  input[type=email], input[type=password], input[type=text], input[type=tel] {\n    height: 44px;\n  }\n\n  /* Media elements */\n  .media{\n    display: block;\n  